---@class StructCombatHeroData
local StructCombatHeroData = LxClass("StructCombatHeroData", nil)
function StructCombatHeroData:StructCombatHeroData()
    self._heros = {}
    self._grids = {}
    self._formationRefId = 0
    -- self.artifactId = 0         --神器Id 0表示为上阵神器Id【G公共支持】删除神器功能相关数据
    self._skillInfo = {}        --宝物信息 CombatTreasureInfo
    self._monster = 0           --怪物阵容, 0 = 不是， 1=是
    self._draconicList = {} --龙纹数据
end

function StructCombatHeroData:CreateByPb(pb)
    local grids=pb.grids
    for i = 1, #grids do
        self._grids[i] = grids[i]
    end
    self._formationRefId = pb.formationRefId
    local heroData=StructHero:New()
    local heros=pb.heros
    for i = 1, #heros do
        heroData:CreateByPb( heros[i])
        self._heros[i]=heroData:GetServerData()
    end

    self._monster = pb.monster

    self._draconicList = {}
    for i = 1, 4 do
        table.insert(self._draconicList, pb.draconicStarRefIds[i])
    end
end

function StructCombatHeroData:GetSkillInfo()
    return self._skillInfo or {}
end

function StructCombatHeroData:CheckIsMonster()
    return self._monster == 1
end

function StructCombatHeroData:GetHeros()
    return self._heros
end

function StructCombatHeroData:GetGrids()
    return self._grids
end
function StructCombatHeroData:GetDraconics()
    return self._draconicList
end

return StructCombatHeroData